final:
module RefModule(
    input clk,
    input reset,
    input serial_in,
    output [3:0] parallel_out
);reg [3:0] unused_shift_reg;

always @(posedge clk) begin
    if (reset) begin
        unused_shift_reg <= 4'b0;
    end else begin
        unused_shift_reg <= {unused_shift_reg[2:0], serial_in};
    end
end

assign parallel_out = unused_shift_reg;

endmodule
